const statusRows  = $('Status Breakdown').all().map(i => i.json);
const typeRows    = $('Type Breakdown').all().map(i => i.json);
const overdueRow  = $('Overdue Breakdown').first().json;
const topOverdue  = $('Top Overdue').all().map(i => i.json);
const zoneRows    = $('Zone Breakdown').all().map(i => i.json);

return [{ json: {
  success: true,
  statusBreakdown: statusRows.map(r => ({ status: r.status || 'Open', count: parseInt(r.cnt || 0) })),
  typeBreakdown:   typeRows.map(r =>   ({ type: r.typeofcomplaint || 'Unknown', count: parseInt(r.cnt || 0) })),
  overdueBreakdown: {
    critical: parseInt(overdueRow.critical || 0),
    high:     parseInt(overdueRow.high     || 0),
    dueToday: parseInt(overdueRow.due_today || 0),
    future:   parseInt(overdueRow.future   || 0),
    noEdc:    parseInt(overdueRow.no_edc   || 0),
  },
  topOverdue,
  zoneBreakdown: zoneRows.map(r => ({ zone: r.zone, count: parseInt(r.cnt || 0) })),
} }];
